args.sparql:
SELECT ?disorder ?disorderLabel ?symptom ?symptomLabel ?treatment ?treatmentLabel WHERE {
  {
    ?disorder wdt:P31 wd:Q218276.
    ?disorder rdfs:label ?disorderLabel.
    FILTER(LANG(?disorderLabel) = "en")
  }
  UNION
  {
    ?disorder wdt:P31 wd:Q209156.
    ?disorder rdfs:label ?disorderLabel.
    FILTER(LANG(?disorderLabel) = "en")
  }
  OPTIONAL {
    ?disorder wdt:P2328 ?symptom.
    ?symptom rdfs:label ?symptomLabel.
    FILTER(LANG(?symptomLabel) = "en")
  }
  OPTIONAL {
    ?disorder wdt:P686 ?treatment.
    ?treatment rdfs:label ?treatmentLabel.
    FILTER(LANG(?treatmentLabel) = "en")
  }
}

SELECT ?disorder ?disorderLabel ?symptom ?symptomLabel ?treatment ?treatmentLabel WHERE {
  ?disorder wdt:P496 ?icd10code .
  FILTER (regex(?icd10code, "^F[34]"))
  ?disorder rdfs:label ?disorderLabel .
  FILTER (LANG(?disorderLabel) = "en")
  OPTIONAL { ?disorder wdt:P2889 ?symptom .
             ?symptom rdfs:label ?symptomLabel .
             FILTER (LANG(?symptomLabel) = "en") }
  OPTIONAL { ?disorder wdt:P686 ?treatment .
             ?treatment rdfs:label ?treatmentLabel .
             FILTER (LANG(?treatmentLabel) = "en") }
}

SELECT ?disorder ?disorderLabel ?symptom ?symptomLabel ?treatment ?treatmentLabel WHERE {
  {
    ?disorder wdt:P279 wd:Q218276
  }
  UNION
  {
    ?disorder wdt:P279 wd:Q209156
  }
  ?disorder rdfs:label ?disorderLabel .
  FILTER (LANG(?disorderLabel) = "en")
  OPTIONAL {
    ?disorder wdt:P2889 ?symptom .
    ?symptom rdfs:label ?symptomLabel .
    FILTER (LANG(?symptomLabel) = "en")
  }
  OPTIONAL {
    ?disorder wdt:P686 ?treatment .
    ?treatment rdfs:label ?treatmentLabel .
    FILTER (LANG(?treatmentLabel) = "en")
  }
}
